@charset "UTF-8";
body {
  margin: 0px;
}

.log-container {
  height: calc(var(--appsmith-ui-height) * 1px);
  width: calc(var(--appsmith-ui-width) * 1px);
  overflow-y: auto;
  font-family: system-ui, sans-serif;
  background: #fff;
  border-radius: var(--appsmith-theme-borderRadius);
  box-shadow: var(--appsmith-theme-boxShadow);
  padding: 20px;
  box-sizing: border-box;
}

/* Centered date header with lines */
.date-separator {
  text-align: center;
  font-weight: 600;
  color: #999;
  font-size: 13px;
  margin: 18px 0 8px;
  position: relative;
}

.date-separator::before,
.date-separator::after {
  content: "";
  position: absolute;
  top: 50%;
  width: 40%;
  height: 1px;
  background: #e0e0e0;
}

.date-separator::before {
  left: 0;
}

.date-separator::after {
  right: 0;
}

/* Each log entry */
.log-entry {
  display: flex;
  flex-direction: column;
  padding: 10px 12px;
  border-radius: 6px;
  margin-bottom: 8px;
  transition: background-color 0.2s ease;
}

/* ✅ Hover background */
.log-entry:hover {
  background-color: #E2F0FF;
}

.log-datetime {
  font-size: 12px;
  color: #666;
  line-height: 1.5;
}

.log-user {
  font-weight: 700;
  font-size: 13px;
  color: #0F1C3F;
  line-height: 1.5;
}

.log-message {
  font-size: 13px;
  color: #222;
  line-height: 1.5;
}

