import React from "https://esm.sh/react@18.2.0";
import ReactDOM from "https://esm.sh/react-dom@18.2.0";
import dayjs from "https://esm.sh/dayjs@1.11.10";

function App() {
  // Pull dynamic logs from Appsmith model or query
  const logs = appsmith.model.data || [];

  // Group by date
  const groupedLogs = logs.reduce((acc, log) => {
    const date = dayjs(log.created_at).format("MM/DD/YYYY");
    if (!acc[date]) acc[date] = [];
    acc[date].push(log);
    return acc;
  }, {});

  // Sort ascending (oldest first)
  const dates = Object.keys(groupedLogs).sort(
    (a, b) => new Date(a) - new Date(b)
  );

  return (
    <div className="log-container">
      {dates.map((date) => (
        <div key={date} className="date-group">
          <div className="date-separator">{date}</div>
          {groupedLogs[date].map((log, i) => (
            <div key={i} className="log-entry">
              <div className="log-datetime">
                {dayjs(log.created_at).format("MM/DD/YYYY hh:mm A")}
              </div>
              <div className="log-user">{log.user_name}</div>
              <div className="log-message">{log.activity_text}</div>
            </div>
          ))}
        </div>
      ))}
    </div>
  );
}

appsmith.onReady(() => {
  ReactDOM.render(<App />, document.getElementById("root"));
});
